    ///       -H "X-Admin-Token: your-admin-token"
    ///
    ///     # Filter by question type
    ///     curl "https://api.example.com/v1/admin/questions/distractor-summary?question_type=pattern" \
    ///       -H "X-Admin-Token: your-admin-token"
    ///
